import { Component, OnInit } from '@angular/core';
import { ActivatedRoute, Router } from '@angular/router';
import { DataService, TestQuestion } from './data.service';

@Component({
  selector: 'app-test',
  templateUrl: './test.component.html',
  styleUrls: ['./test.component.css'],
})
export class TestComponent implements OnInit {
  questions: TestQuestion[] = [];
  current = 0;
  answers: string[] = [];
  loading = true;
  error = '';
  categoryIds: string[] = [];

  constructor(private route: ActivatedRoute, private router: Router, private dataService: DataService) {}

  ngOnInit(): void {
    this.route.queryParams.subscribe((params) => {
      this.categoryIds = [];
      if (params['categorie']) {
        try {
          this.categoryIds = JSON.parse(params['categorie']);
        } catch {
          this.categoryIds = [];
        }
      }
      this.loadQuestions();
    });
  }

  loadQuestions(): void {
    this.loading = true;
    this.error = '';
    this.dataService.loadData().subscribe({
      next: () => {
        this.questions = this.dataService.getQuestions(this.categoryIds);
        if (!this.questions.length) {
          this.error = 'Nessuna domanda trovata per queste categorie.';
        }
        this.loading = false;
      },
      error: () => {
        this.loading = false;
        this.error = 'Errore di caricamento. Riprova più tardi.';
      },
    });
  }

  get progressPercent(): number {
    return this.questions.length ? Math.round((this.current / this.questions.length) * 100) : 0;
  }

  answer(rule?: string): void {
    if (rule) {
      this.answers.push(rule);
    }
    this.current += 1;
    if (this.current >= this.questions.length) {
      this.finish();
    }
  }

  finish(): void {
    const queryParams: Record<string, string> = {
      regole: JSON.stringify(this.answers),
    };
    if (this.categoryIds.length) {
      queryParams['categorie'] = JSON.stringify(this.categoryIds);
    }
    this.router.navigate(['/test-risultati'], { queryParams });
  }
}
<nav class="navbar-custom d-flex align-items-center justify-content-between flex-wrap gap-2">
  <a class="navbar-brand-text text-decoration-none" routerLink="/">🌿 Educazione Digitale Familiare</a>
  <a routerLink="/" class="btn-search" style="text-decoration:none;font-size:0.9rem;">Indietro</a>
</nav>

<section class="test-shell">
  <div class="section-label">Patto Familiare</div>
  <h2 class="section-title">Crea il tuo patto familiare</h2>
  <p class="section-sub">Rispondi alle domande. Alla fine riceverai le regole consigliate per la tua famiglia.</p>

  <div class="progress-bar-wrap">
    <div class="progress-bar" [style.width]="progressPercent + '%' "></div>
  </div>

  <div *ngIf="loading" class="info-box">Caricamento domande...</div>
  <div *ngIf="error" class="info-box info-box-error">{{ error }}</div>

  <div *ngIf="!loading && !error && questions.length" class="question-card">
    <div class="question-counter">Domanda {{ current + 1 }} di {{ questions.length }}</div>
    <h3 class="question-title">{{ questions[current].domanda }}</h3>
    <div class="question-actions">
      <button class="btn-primary-hero" (click)="answer(questions[current].se_si)">SI</button>
      <button class="btn-secondary-hero" (click)="answer(questions[current].se_no)">NO</button>
    </div>
  </div>
</section>
